import * as t from "io-ts";
import { SuiBuildOptions } from "./suiBuildOptions";
import { BaseIntent } from "./baseIntent";
import { intentTypes } from "./intentType";

/**
 * @title SUI Custom Tx Intent
 */
export const SuiCustomTxIntent = t.intersection([
  BaseIntent,
  SuiBuildOptions,
  t.type({
    intentType: intentTypes.customTx,
    rawTx: t.string,
  }),
]);

export type SuiCustomTxIntent = t.TypeOf<typeof SuiCustomTxIntent>;
